import React from 'react';

interface CouponCardProps {
  title: string;
  expiry: string;
  maxDiscount: number;
  discountRate: number;
  onUse: () => void;
}

const CouponCard: React.FC<CouponCardProps> = ({ title, expiry, maxDiscount, discountRate, onUse }) => {
  return (
    <div className="relative border rounded-lg flex flex-col gap-2 bg-white overflow-visible">
      <div className="flex flex-col justify-between items-center px-2">
        <div className="flex flex-col w-full py-3 px-2">
          <div className="font-semibold mb-1">{title}</div>
          <div className="text-xs text-gray-500">{expiry}</div>
          <div className="text-xs text-gray-400">(최대 {maxDiscount.toLocaleString()}원 할인)</div>
        </div>
        <div className="flex flex-row items-center justify-between w-full">
          <div className="text-orange-600 font-bold text-sm">사용 가능</div>
          <div className="text-blue-600 font-bold text-sm">{discountRate}%</div>
        </div>
      </div>
      {/* SVG 마스킹 효과: 작은 동그라미 구멍 */}
      <svg
        width="100%"
        height="24"
        viewBox="0 0 100 24"
        className="absolute left-0 right-0 -bottom-3"
        style={{ minWidth: '100%', zIndex: 10 }}
        preserveAspectRatio="none"
      >
        <defs>
          <mask id="couponMask">
            <rect x="0" y="0" width="100" height="24" fill="white" />
            <circle cx="0" cy="12" r="6" fill="black" />
            <circle cx="100" cy="12" r="6" fill="black" />
          </mask>
        </defs>
        <rect x="0" y="0" width="100" height="24" fill="white" mask="url(#couponMask)" />
        <line x1="6" y1="12" x2="94" y2="12" stroke="#d1d5db" strokeDasharray="4 4" strokeWidth="2" />
      </svg>
      <button
        className="w-full bg-orange-600 text-white py-2 rounded-lg font-semibold hover:bg-orange-700 transition"
        onClick={onUse}
      >
        쿠폰 사용
      </button>
    </div>
  );
};

export default CouponCard;
